-- TABLE : DCF_RAWDATA.DWH.DIM_STAFF_PERSON_OFFICE_ASSIGNS_INFO
create or replace TABLE DIM_STAFF_PERSON_OFFICE_ASSIGNS_INFO (
	STAFF_PERSON_OFFICE_ASSIGNS_INFO_ID NUMBER(10,0) NOT NULL autoincrement start 1 increment 1 order,
	ASSIGNMENT_TYPE_DESC VARCHAR(80),
	ASSIGNMENT_TYPE_AV_ID VARCHAR(10),
	ASSIGNMENT_SUB_TYPE_DESC VARCHAR(80),
	ASSIGNMENT_SUB_TYPE_AV_ID VARCHAR(10),
	JBPM_PROCESS_OUTCOME_CODE_DESC VARCHAR(80),
	JBPM_PROCESS_OUTCOME_CODE_AV_ID VARCHAR(10),
	WORKLOAD_TYPE_DESC VARCHAR(80),
	WORKLOAD_TYPE_AV_ID VARCHAR(80),
	CREATED_DATE TIMESTAMP_NTZ(9),
	UPDATED_DATE TIMESTAMP_NTZ(9),
	DELETED_DATE TIMESTAMP_NTZ(9),
	CHECKSUM VARCHAR(99),
	primary key (STAFF_PERSON_OFFICE_ASSIGNS_INFO_ID)
);

